// Simple script regex to extract scripts
const scriptRegex = /<script\b[^>]*>([\s\S]*?)<\/script>/gi;
let match;
let count = 0;

while ((match = scriptRegex.exec(content)) !== null) {
    const js = match[1];
    if (js.trim().length === 0) continue;
    count++;
    try {
        // Try parsing the JS by creating a function with it
        new Function(js);
        console.log(`Script block ${count} parsed successfully.`);
    } catch (e) {
        console.error(`Error parsing script block ${count}:`, e.message);
        // Find line number of error in the script block
        // and match against file lines
        console.error(e.stack);
    }
}

