}

const fs = require('fs');
const content = fs.readFileSync('g:/quizlish/index.html', 'utf8');

// A simple tag matching check
const stack = [];
const tagRegex = /<\/?([a-z0-9:-]+)(?:\s+[^>]*)?>/gi;
let match;
let errors = 0;

// Self-closing HTML tags
const selfClosing = new Set([
    'area', 'base', 'br', 'col', 'embed', 'hr', 'img', 'input', 
    'link', 'meta', 'param', 'source', 'track', 'wbr'
]);

while ((match = tagRegex.exec(content)) !== null) {
    const fullTag = match[0];
    const tagName = match[1].toLowerCase();
    const isClosing = fullTag.startsWith('</');

    if (selfClosing.has(tagName)) continue;
    // Skip comments and doctype
    if (tagName.startsWith('!') || tagName.startsWith('?')) continue;

    if (isClosing) {
        if (stack.length === 0) {
            console.error(`Error: Extra closing tag </${tagName}> without opening tag near index ${match.index}`);
            errors++;
        } else {
            const lastOpen = stack.pop();
            if (lastOpen.name !== tagName) {
                console.error(`Error: Mismatched tag near index ${match.index}. Expected </${lastOpen.name}> (opened near ${lastOpen.index}), but found </${tagName}>`);
                errors++;
            }
        }
    } else {
        stack.push({ name: tagName, index: match.index });
    }
}

if (stack.length > 0) {
    console.error(`Error: Unclosed tags remaining:`, stack.map(t => `${t.name} (opened near ${t.index})`));
    errors += stack.length;
}

if (errors === 0) {
    console.log("No tag mismatch errors detected.");
} else {
    console.log(`Total tag errors: ${errors}`);
}

