// Supabase Database and Authentication integration
const supabaseUrl = 'https://hbylodrkprppisskqaup.supabase.co';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImhieWxvZHJrcHJwcGlzc2txYXVwIiwicm9sZSI6ImFub24iLCJpYXQiOjE3ODE0MjkyMzMsImV4cCI6MjA5NzAwNTIzM30.XLW3N0asYYlr2SSsntr7Z37jOp-MpNeNkseXqZ-Bxqw';
const supabaseClient = window.supabase ? window.supabase.createClient(supabaseUrl, supabaseKey) : null;

let isSignUpMode = false;
let currentUser = null;

if (supabaseClient) {
    // Listen to auth changes Reactively
    supabaseClient.auth.onAuthStateChange((event, session) => {
        if (session && session.user) {
            currentUser = {
                name: (session.user.user_metadata && session.user.user_metadata.full_name) || session.user.email.split('@')[0],
                email: session.user.email
            };
        } else {
            currentUser = null;
        }
        syncAuthState();
    });
}

function getLoggedInUser() {
    return currentUser;
}

function openAuthModal() {
    const modal = document.getElementById('auth-modal');
    modal.classList.remove('hidden');
    setTimeout(() => {
        modal.classList.remove('opacity-0');
        modal.querySelector('div').classList.remove('scale-95');
    }, 10);
}

function closeAuthModal() {
    const modal = document.getElementById('auth-modal');
    modal.classList.add('opacity-0');
    modal.querySelector('div').classList.add('scale-95');
    setTimeout(() => {
        modal.classList.add('hidden');
        document.getElementById('auth-form').reset();
    }, 300);
}

function toggleAuthMode() {
    isSignUpMode = !isSignUpMode;
    const title = document.getElementById('auth-modal-title');
    const subtitle = document.getElementById('auth-modal-subtitle');
    const nameContainer = document.getElementById('auth-name-container');
    const nameInput = document.getElementById('auth-name-input');
    const submitBtn = document.getElementById('auth-submit-btn');
    const toggleText = document.getElementById('auth-toggle-text');
    const toggleBtn = document.getElementById('auth-toggle-btn');

    if (isSignUpMode) {
        title.innerText = 'Create Account';
        subtitle.innerText = 'Sign up to save progress and unlock features.';
        nameContainer.classList.remove('hidden');
        nameInput.required = true;
        submitBtn.innerText = 'Sign Up';
        toggleText.innerText = 'Already have an account?';
        toggleBtn.innerText = 'Sign In';
    } else {
        title.innerText = 'Welcome Back';
        subtitle.innerText = 'Sign in to track your test scores and review explanations.';
        nameContainer.classList.add('hidden');
        nameInput.required = false;
        submitBtn.innerText = 'Sign In';
        toggleText.innerText = "Don't have an account?";
        toggleBtn.innerText = 'Sign Up';
    }
}

function handleAuthClick() {
    const user = getLoggedInUser();
    if (user) {
        const dropdown = document.getElementById('user-profile-dropdown');
        dropdown.classList.toggle('hidden');
        dropdown.classList.toggle('flex');
    } else {
        openAuthModal();
    }
}

async function handleAuthSubmit(event) {
    event.preventDefault();
    if (!supabaseClient) {
        alert("Database is currently initializing or unavailable. Please try again later.");
        return;
    }

    const email = document.getElementById('auth-email-input').value;
    const password = document.getElementById('auth-password-input').value;
    const submitBtn = document.getElementById('auth-submit-btn');

    submitBtn.disabled = true;
    submitBtn.innerText = isSignUpMode ? 'Signing Up...' : 'Signing In...';

    try {
        if (isSignUpMode) {
            const name = document.getElementById('auth-name-input').value;
            const { data, error } = await supabaseClient.auth.signUp({
                email: email,
                password: password,
                options: {
                    data: {
                        full_name: name
                    }
                }
            });
            if (error) throw error;
            alert("Signup successful! Please check your email to verify your account or sign in.");
        } else {
            const { data, error } = await supabaseClient.auth.signInWithPassword({
                email: email,
                password: password
            });
            if (error) throw error;
            alert("Logged in successfully!");
        }
        closeAuthModal();
    } catch (err) {
        console.error("Auth Error:", err);
        alert("Authentication failed: " + err.message);
    } finally {
        submitBtn.disabled = false;
        submitBtn.innerText = isSignUpMode ? 'Sign Up' : 'Sign In';
    }
}

async function handleSignOut() {
    if (!supabaseClient) return;
    try {
        const { error } = await supabaseClient.auth.signOut();
        if (error) throw error;
        const dropdown = document.getElementById('user-profile-dropdown');
        dropdown.classList.add('hidden');
        dropdown.classList.remove('flex');
        alert('Successfully signed out!');
    } catch (err) {
        alert('Sign out failed: ' + err.message);
    }
}

async function saveScoreToDatabase(email, category, quizName, score, totalQuestions) {
    if (!supabaseClient) return;
    try {
        const { data, error } = await supabaseClient
            .from('quiz_scores')
            .insert([
                { 
                    email: email, 
                    category: category, 
                    quiz_name: quizName, 
                    score: score, 
                    total_questions: totalQuestions,
                    created_at: new Date().toISOString()
                }
            ]);
        if (error) {
            console.error("Supabase DB Insert Error:", error);
        } else {
            console.log("Score logged in database successfully!");
        }
    } catch (err) {
        console.error("Failed to connect to Supabase DB:", err);
    }
}

