            if (error) throw error;
            alert("Signup successful! Please check your email to verify your account or sign in.");
        } else {
            const { data, error } = await supabase.auth.signInWithPassword({
                email: email,
                password: password
            });
            if (error) throw error;
            alert("Logged in successfully!");
        }
        closeAuthModal();
    } catch (err) {
        console.error("Auth Error:", err);
        alert("Authentication failed: " + err.message);
    } finally {
        submitBtn.disabled = false;
        submitBtn.innerText = isSignUpMode ? 'Sign Up' : 'Sign In';
    }
}

async function handleSignOut() {
    if (!supabase) return;
    try {
        const { error } = await supabase.auth.signOut();
        if (error) throw error;
        const dropdown = document.getElementById('user-profile-dropdown');
        dropdown.classList.add('hidden');
        dropdown.classList.remove('flex');
        alert('Successfully signed out!');
    } catch (err) {
        alert('Sign out failed: ' + err.message);
    }
}

async function saveScoreToDatabase(email, category, quizName, score, totalQuestions) {
    if (!supabase) return;
    try {
        const { data, error } = await supabase
            .from('quiz_scores')
            .insert([
