args.ReplacementContent:
let isSignUpMode = false;
let currentUser = null;

if (supabaseClient) {
    // Listen to auth changes Reactively
    supabaseClient.auth.onAuthStateChange((event, session) => {
        if (session && session.user) {
            currentUser = {
                name: (session.user.user_metadata && session.user.user_metadata.full_name) || session.user.email.split('@')[0],
                email: session.user.email
            };
        } else {
            currentUser = null;
            if (screens.profile && !screens.profile.classList.contains('hidden')) {
                showHome();
            }
        }
        syncAuthState();
    });
}

function getLoggedInUser() {
    return currentUser;
}

function openAuthModal() {
    const modal = document.getElementById('auth-modal');
    modal.classList.remove('hidden');
    setTimeout(() => {
        modal.classList.remove('opacity-0');
        modal.querySelector('div').classList.remove('scale-95');
    }, 10);
}

function closeAuthModal() {
    const modal = document.getElementById('auth-modal');
    modal.classList.add('opacity-0');
    modal.querySelector('div').classList.add('scale-95');
    setTimeout(() => {
        modal.classList.add('hidden');
        document.getElementById('auth-form').reset();
    }, 300);
}

function setAuthTab(tab) {
    const tabSignin = document.getElementById('tab-signin');
    const tabSignup = document.getElementById('tab-signup');
    const title = document.getElementById('auth-modal-title');
    const subtitle = document.getElementById('auth-modal-subtitle');
    const nameContainer = document.getElementById('auth-name-container');
    const nameInput = document.getElementById('auth-name-input');
    const submitBtn = document.getElementById('auth-submit-btn');

    if (tab === 'signup') {
        isSignUpMode = true;
        tabSignup.className = "flex-1 pb-3 text-center font-black text-lg border-b-2 border-blue-600 text-blue-600 dark:text-blue-400 focus:outline-none transition-all";
        tabSignin.className = "flex-1 pb-3 text-center font-bold text-lg border-b-2 border-transparent text-slate-400 dark:text-slate-500 focus:outline-none transition-all";

        title.innerText = 'Create Account';
        subtitle.innerText = 'Sign up to save progress and unlock features.';
        nameContainer.classList.remove('hidden');
        nameInput.required = true;
        submitBtn.innerText = 'Sign Up';
    } else {
        isSignUpMode = false;
        tabSignin.className = "flex-1 pb-3 text-center font-black text-lg border-b-2 border-blue-600 text-blue-600 dark:text-blue-400 focus:outline-none transition-all";
        tabSignup.className = "flex-1 pb-3 text-center font-bold text-lg border-b-2 border-transparent text-slate-400 dark:text-slate-500 focus:outline-none transition-all";

        title.innerText = 'Welcome Back';
        subtitle.innerText = 'Sign in to track your test scores and review explanations.';
        nameContainer.classList.add('hidden');
        nameInput.required = false;
        submitBtn.innerText = 'Sign In';
    }
}

function toggleAuthMode() {
    setAuthTab(isSignUpMode ? 'signin' : 'signup');
}

function handleAuthClick() {
    const user = getLoggedInUser();
    if (user) {
        const dropdown = document.getElementById('user-profile-dropdown');
        dropdown.classList.toggle('hidden');
        dropdown.classList.toggle('flex');
    } else {
        openAuthModal();
    }
}

async function handleAuthSubmit(event) {
    event.preventDefault();
    if (!supabaseClient) {
        alert("Database is currently initializing or unavailable. Please try again later.");
        return;
    }

    const email = document.getElementById('auth-email-input').value;
    const password = document.getElementById('auth-password-input').value;
    const submitBtn = document.getElementById('auth-submit-btn');

    submitBtn.disabled = true;
    submitBtn.innerText = isSignUpMode ? 'Signing Up...' : 'Signing In...';

    try {
        if (isSignUpMode) {
            const name = document.getElementById('auth-name-input').value;
            const { data, error } = await supabaseClient.auth.signUp({
                email: email,
                password: password,
                options: {
                    data: {
                        full_name: name
                    }
                }
            });
            if (error) throw error;
            alert("Signup successful! Please check your email to verify your account or sign in.");
        } else {
            const { data, error } = await supabaseClient.auth.signInWithPassword({
                email: email,
                password: password
            });
            if (error) throw error;
            alert("Logged in successfully!");
        }
        closeAuthModal();
    } catch (err) {
        console.error("Auth Error:", err);
        alert("Authentication failed: " + err.message);
    } finally {
        submitBtn.disabled = false;
        submitBtn.innerText = isSignUpMode ? 'Sign Up' : 'Sign In';
    }
}

async function handleSignOut() {
    if (!supabaseClient) return;
    try {
        const { error } = await supabaseClient.auth.signOut();
        if (error) throw error;
        const dropdown = document.getElementById('user-profile-dropdown');
        dropdown.classList.add('hidden');
        dropdown.classList.remove('flex');
        alert('Successfully signed out!');
    } catch (err) {
        alert('Sign out failed: ' + err.message);
    }
}

async function saveScoreToDatabase(email, category, quizName, score, totalQuestions) {
    if (!supabaseClient) return;
    try {
        const { data, error } = await supabaseClient
            .from('quiz_scores')
            .insert([
                { 
                    email: email, 
                    category: category, 
                    quiz_name: quizName, 
                    score: score, 
                    total_questions: totalQuestions,
                    created_at: new Date().toISOString()
                }
            ]);
        if (error) {
            console.error("Supabase DB Insert Error:", error);
        } else {
            console.log("Score logged in database successfully!");
        }
    } catch (err) {
        console.error("Failed to connect to Supabase DB:", err);
    }
}

function showProfile() {
    const dropdown = document.getElementById('user-profile-dropdown');
    if (dropdown) {
        dropdown.classList.add('hidden');
        dropdown.classList.remove('flex');
    }
    showScreen('profile');
    loadProfileStats();
}

async function loadProfileStats() {
    const user = getLoggedInUser();
    if (!user) return;

    document.getElementById('profile-user-name').innerText = user.name;
    document.getElementById('profile-user-email').innerText = user.email;
    document.getElementById('profile-avatar').innerText = user.name.charAt(0).toUpperCase();

    const scoresTableBody = document.getElementById('scores-table-body');
    const noScoresMsg = document.getElementById('no-scores-message');
    scoresTableBody.innerHTML = '';

    if (!supabaseClient) return;

    try {
        const { data, error } = await supabaseClient
            .from('quiz_scores')
            .select('*')
            .eq('email', user.email)
            .order('created_at', { ascending: false });

        if (error) throw error;

        if (!data || data.length === 0) {
            noScoresMsg.classList.remove('hidden');
            document.getElementById('stats-tests-count').innerText = '0';
            document.getElementById('stats-average-score').innerText = '0%';
            document.getElementById('stats-highest-score').innerText = '0%';
            return;
        }

        noScoresMsg.classList.add('hidden');
        document.getElementById('stats-tests-count').innerText = data.length;

        let totalScoreSum = 0;
        let highestScore = 0;

        data.forEach(row => {
            const percentage = Math.round((row.score / row.total_questions) * 100);
            totalScoreSum += percentage;
            if (percentage > highestScore) {
                highestScore = percentage;
            }

            const tr = document.createElement('tr');
            tr.className = "border-b border-slate-100 dark:border-slate-700 hover:bg-slate-50/50 dark:hover:bg-slate-700/50 transition-colors";

            const dateStr = new Date(row.created_at).toLocaleDateString(undefined, {
                year: 'numeric',
                month: 'short',
                day: 'numeric'
            });

            const categoryPretty = categoryNames[row.category] || row.category;

            tr.innerHTML = `
