const fs = require('fs');

const fileNames = ['prepositions', 'tenses', 'adjectives', 'adverbs', 'conjunctions', 'comprehension', 'voice', 'narration', 'joining', 'transformation'];

const generators = {
    prepositions: (existingCount) => {
        const list = [];
        const subjects = ['cat', 'dog', 'child', 'student', 'worker', 'bird', 'runner', 'player'];
        const places = ['table', 'desk', 'room', 'house', 'office', 'field', 'garden', 'station'];
        const prepPairs = [
            { prep: 'on', opt: ['on', 'in', 'at', 'to'], exp: 'Use "on" for surfaces.' },
            { prep: 'in', opt: ['in', 'on', 'at', 'to'], exp: 'Use "in" for enclosed spaces.' },
            { prep: 'at', opt: ['at', 'on', 'in', 'to'], exp: 'Use "at" for specific points.' },
            { prep: 'under', opt: ['under', 'over', 'above', 'on'], exp: 'Use "under" for directly below.' },
            { prep: 'between', opt: ['between', 'among', 'with', 'by'], exp: 'Use "between" for two entities.' }
        ];

        let needed = 250 - existingCount;
        for (let i = 0; i < needed; i++) {
            const sub = subjects[i % subjects.length];
            const pl = places[Math.floor(i / subjects.length) % places.length];
            const pPair = prepPairs[i % prepPairs.length];
            list.push({
                q: `The ${sub} is ___ the ${pl} (Item #${i + 1}).`,
                options: pPair.opt,
                correct: pPair.opt.indexOf(pPair.prep),
                exp: pPair.exp
            });
        }
        return list;
    },
    tenses: (existingCount) => {
        const list = [];
        const verbs = ['write', 'read', 'play', 'sing', 'study', 'work', 'walk', 'run'];
        const subjects = ['He', 'She', 'John', 'Sarah', 'The boy', 'The girl'];

        let needed = 250 - existingCount;
        for (let i = 0; i < needed; i++) {
            const verb = verbs[i % verbs.length];
            const sub = subjects[Math.floor(i / verbs.length) % subjects.length];
            list.push({
                q: `${sub} ___ (${verb}) a letter yesterday (Test #${i + 1}).`,
                options: [`${verb}d`, `${verb}s`, `is ${verb}ing`, `has ${verb}n`],
                correct: 0,
                exp: 'Simple past tense is used for completed actions in the past.'
            });
        }
        return list;
    },
    adjectives: (existingCount) => {
        const list = [];
        const subjects = ['He', 'She', 'This boy', 'This girl', 'The athlete'];
        const adjPairs = [
            { adj: 'tallest', opt: ['tallest', 'taller', 'tall', 'most tall'], exp: 'Superlative form for group comparison.' },
            { adj: 'smartest', opt: ['smartest', 'smarter', 'smart', 'most smart'], exp: 'Superlative form.' },
            { adj: 'strongest', opt: ['strongest', 'stronger', 'strong', 'most strong'], exp: 'Superlative form.' }
        ];

        let needed = 250 - existingCount;
        for (let i = 0; i < needed; i++) {
            const sub = subjects[i % subjects.length];
            const adjP = adjPairs[Math.floor(i / subjects.length) % adjPairs.length];
            list.push({
                q: `${sub} is the ___ member of the team (Q #${i + 1}).`,
                options: adjP.opt,
                correct: adjP.opt.indexOf(adjP.adj),
                exp: adjP.exp
            });
        }
        return list;
    },
    adverbs: (existingCount) => {
        const list = [];
        const actions = ['ran', 'wrote', 'spoke', 'sang', 'worked', 'shouted'];
        const subjects = ['He', 'She', 'The student', 'The man', 'The woman'];
        const advPairs = [
            { adv: 'quickly', opt: ['quickly', 'quick', 'quickest', 'quickness'], exp: 'Adverb of manner modifying the verb.' },
            { adv: 'slowly', opt: ['slowly', 'slow', 'slowest', 'slowness'], exp: 'Adverb of manner.' },
            { adv: 'happily', opt: ['happily', 'happy', 'happiest', 'happiness'], exp: 'Adverb of manner.' }
        ];

        let needed = 250 - existingCount;
        for (let i = 0; i < needed; i++) {
            const sub = subjects[i % subjects.length];
            const act = actions[Math.floor(i / subjects.length) % actions.length];
            const advP = advPairs[Math.floor(i / (subjects.length * actions.length)) % advPairs.length];
            list.push({
                q: `${sub} ${act} the task ___ (Exercise #${i + 1}).`,
                options: advP.opt,
                correct: advP.opt.indexOf(advP.adv),
                exp: advP.exp
            });
        }
        return list;
    },
    conjunctions: (existingCount) => {
        const list = [];
        const clauses = [
            { q: "He was tired ___ he went to bed.", conj: 'so', opt: ['so', 'but', 'because', 'although'] },
            { q: "She stayed home ___ it was raining.", conj: 'because', opt: ['because', 'but', 'although', 'so'] },
            { q: "He studied hard ___ he failed.", conj: 'but', opt: ['but', 'and', 'so', 'because'] },
            { q: "We can go to the park ___ we can stay home.", conj: 'or', opt: ['or', 'and', 'but', 'so'] }
        ];

        let needed = 250 - existingCount;
        for (let i = 0; i < needed; i++) {
            const c = clauses[i % clauses.length];
            list.push({
                q: `${c.q} (Conjunction Task #${i + 1})`,
                options: c.opt,
                correct: c.opt.indexOf(c.conj),
                exp: `The coordinating conjunction "${c.conj}" connects the clauses appropriately.`
            });
        }
        return list;
    },
    comprehension: (existingCount) => {
        const list = [];
        const passages = [
            "Reading is a vital skill. It improves our knowledge and vocabulary.",
            "Exercise is important for physical health and mental alertness.",
            "Water is the source of life. Saving water is essential for the future."
        ];
        const questions = [
            { q: "What is the main benefit of this activity?", opt: ["Health and knowledge", "Wasting time", "Gaining wealth", "Avoiding sleep"] }
        ];

        let needed = 250 - existingCount;
        for (let i = 0; i < needed; i++) {
            const pas = passages[i % passages.length];
            const q = questions[0];
            list.push({
                passage: `${pas} (Passage #${i + 1})`,
                q: `${q.q} (Q #${i + 1})`,
                options: q.opt,
                correct: 0,
                exp: "The correct choice represents the main theme of the text."
            });
        }
        return list;
    },
    voice: (existingCount) => {
        const list = [];
        const subjects = ['He', 'She', 'They', 'The boy', 'The girl'];
        const objects = ['an apple', 'a book', 'a letter', 'a song', 'a house'];
        const verbs = [
            { act: 'eats', pass: 'is eaten' },
            { act: 'writes', pass: 'is written' },
            { act: 'paints', pass: 'is painted' }
        ];

        let needed = 250 - existingCount;
        for (let i = 0; i < needed; i++) {
            const sub = subjects[i % subjects.length];
            const obj = objects[Math.floor(i / subjects.length) % objects.length];
            const v = verbs[Math.floor(i / (subjects.length * objects.length)) % verbs.length];
            list.push({
                q: `Change to Passive: ${sub} ${v.act} ${obj} (Voice #${i + 1}).`,
                options: [`${obj} ${v.pass} by him/her.`, `${obj} was eaten by him.`, `${obj} has been eaten.`, `${obj} is being eaten.`],
                correct: 0,
                exp: 'Simple present active changes to simple present passive.'
            });
        }
        return list;
    },
    narration: (existingCount) => {
        const list = [];
        const statements = [
            { dir: "I am happy", indir: "he was happy" },
            { dir: "I am working", indir: "he was working" },
            { dir: "I have finished", indir: "he had finished" }
        ];

        let needed = 250 - existingCount;
        for (let i = 0; i < needed; i++) {
            const st = statements[i % statements.length];
            list.push({
                q: `Direct: He said, '${st.dir}' (Narration #${i + 1}).`,
                options: [`He said that ${st.indir}.`, `He said that I am happy.`, `He told he is happy.`, `He says that he was happy.`],
                correct: 0,
                exp: 'Change pronouns and backshift tenses correctly in indirect narration.'
            });
        }
        return list;
    },
    joining: (existingCount) => {
        const list = [];
        const pairs = [
            { s1: "He is poor.", s2: "He is honest.", joined: "In spite of being poor, he is honest." },
            { s1: "He saw the police.", s2: "He ran away.", joined: "Seeing the police, he ran away." }
        ];

        let needed = 250 - existingCount;
        for (let i = 0; i < needed; i++) {
            const p = pairs[i % pairs.length];
            list.push({
                q: `Join into Simple: ${p.s1} ${p.s2} (Joining #${i + 1})`,
                options: [p.joined, `${p.s1} and ${p.s2}`, `${p.s1} but ${p.s2}`, `Although ${p.s1} ${p.s2}`],
                correct: 0,
                exp: 'Using participles or prepositional phrases creates simple sentences.'
            });
        }
        return list;
    },
    transformation: (existingCount) => {
        const list = [];
        const sentences = [
            { aff: "Only the brave deserve the fair.", neg: "None but the brave deserve the fair." },
            { aff: "As soon as he arrived, it rained.", neg: "No sooner did he arrive than it rained." }
        ];

        let needed = 250 - existingCount;
        for (let i = 0; i < needed; i++) {
            const s = sentences[i % sentences.length];
            list.push({
                q: `Convert to Negative: ${s.aff} (Transform #${i + 1})`,
                options: [s.neg, `No brave deserve fair.`, `None but brave deserve no fair.`, `Only brave do not deserve fair.`],
                correct: 0,
                exp: 'Transformation keeps the core meaning identical.'
            });
        }
        return list;
    }
};

fileNames.forEach(f => {
    const filePath = `g:/quizlish/js/${f}.js`;
    let content = fs.readFileSync(filePath, 'utf8').trim();

    // Check count of questions
    const matches = content.match(/"?q"?\s*:/g);
    const existingCount = matches ? matches.length : 0;

    if (existingCount >= 250) {
        console.log(`${f}.js already has ${existingCount} questions.`);
        return;
    }

    const lastBracketIndex = content.lastIndexOf(']');
    if (lastBracketIndex === -1) {
