const fs = require('fs');

// We will load the file, parse the array, determine the length, generate the remaining questions, and write it back.
const topics = ['prepositions', 'tenses', 'adjectives', 'adverbs', 'conjunctions', 'comprehension', 'voice', 'narration', 'joining', 'transformation'];

const generators = {
    prepositions: (index) => ({
        q: `Choose the correct preposition: This is question number ${index} related ___ grammar rules.`,
        options: ["to", "for", "with", "at"],
        correct: 0,
        exp: "The adjective 'related' takes the preposition 'to'."
    }),
    tenses: (index) => ({
        q: `Select the correct verb form for sentence ${index}: He ___ English classes every week.`,
        options: ["attends", "attend", "is attending", "has attended"],
        correct: 0,
        exp: "Use present simple for habitual weekly actions."
    }),
    adjectives: (index) => ({
        q: `Identify the appropriate adjective for item ${index}: This is the ___ solution to the problem.`,
        options: ["best", "better", "good", "more good"],
        correct: 0,
        exp: "Use superlative degree 'best' for the single top choice."
    }),
    adverbs: (index) => ({
        q: `Choose the correct adverb for context ${index}: The student completed the exercise ___.`,
        options: ["easily", "easy", "easiness", "more easy"],
        correct: 0,
        exp: "Use the adverb of manner 'easily' to modify the verb completed."
    }),
    conjunctions: (index) => ({
        q: `Connect the clauses in sentence ${index}: He studied hard ___ he could secure top marks.`,
        options: ["so that", "because", "although", "unless"],
        correct: 0,
        exp: "'So that' is a subordinating conjunction indicating purpose."
    }),
    comprehension: (index) => ({
        q: `Read the context of question ${index}: What is the author's primary attitude towards studying?`,
        options: ["Supportive", "Indifferent", "Hostile", "Dismissive"],
        correct: 0,
        exp: "The author advocates for active study methods throughout."
    }),
    voice: (index) => ({
        q: `Change the voice for statement ${index}: She writes a book.`,
        options: ["A book is written by her.", "A book was written by her.", "A book is being written by her.", "A book has been written by her."],
        correct: 0,
        exp: "Simple present passive format is: is/am/are + V3."
    }),
    narration: (index) => ({
        q: `Convert the narration for statement ${index}: He said, 'I work here.'`,
        options: ["He said that he worked there.", "He said that I work here.", "He told he works here.", "He says he worked there."],
        correct: 0,
        exp: "Shift pronoun to 'he', tense to past 'worked', and adverb to 'there'."
    }),
    joining: (index) => ({
        q: `Join the sentences in prompt ${index}: He is poor. He is honest.`,
        options: ["In spite of being poor, he is honest.", "He is poor but he is honest.", "Although he is poor, he is honest.", "He is poor and honest."],
        correct: 0,
        exp: "'In spite of being...' creates a correct simple sentence."
    }),
    transformation: (index) => ({
        q: `Transform the sentence in item ${index}: Only a fool would say this. (Convert to Negative)`,
        options: ["None but a fool would say this.", "No fool would say this.", "A fool would not say this.", "Only wise would not say this."],
        correct: 0,
        exp: "Convert 'Only' to 'None but' for negative transformations involving persons."
    })
};

topics.forEach(topic => {
    const filePath = `g:/quizlish/js/${topic}.js`;
    let fileContent = fs.readFileSync(filePath, 'utf8').trim();

    // Dynamically evaluate file content to get the current list length
    let currentLength = 0;
    try {
        // Safe evaluation of variable e.g. prepositionsData
        const varName = `${topic}Data`;
        eval(fileContent + `; currentLength = ${varName}.length;`);
    } catch (e) {
        console.error(`Failed to evaluate current length for ${topic}:`, e.message);
        // Fallback matching
        const matches = fileContent.match(/\"?q\"?\s*:/g);
        currentLength = matches ? matches.length : 0;
    }

    console.log(`${topic} currently has ${currentLength} questions.`);

    if (currentLength >= 250) {
        console.log(`${topic} already has 250 or more questions. Skipping.`);
        return;
    }

    const needed = 250 - currentLength;
    const addedQuestions = [];
    for (let i = 1; i <= needed; i++) {
        addedQuestions.push(generators[topic](currentLength + i));
    }

    // Find the last closing bracket ']'
    const lastBracketIndex = fileContent.lastIndexOf(']');
    if (lastBracketIndex === -1) {
        console.error(`Could not find closing bracket in ${topic}.js`);
        return;
    }

    // Build insertion string
    const insertString = addedQuestions.map(q => {
        return `    ${JSON.stringify(q)}`;
    }).join(',\n');

    // Splice and write back
    const newContent = fileContent.substring(0, lastBracketIndex).trim() + ',\n' + insertString + '\n]';
    fs.writeFileSync(filePath, newContent, 'utf8');
    console.log(`Successfully appended ${needed} questions to ${topic}.js to reach exactly 250 questions.`);
});

