const fs = require('fs');

const pages = [
  'index.html', 'privacy.html', 'terms.html', 'feedback.html', 
  'writings.html', 'profile.html', 'prepositions.html', 'tenses.html', 
  'adjectives.html', 'adverbs.html', 'conjunctions.html', 'voice.html', 
  'narration.html', 'joining.html', 'transformation.html', 'comprehension.html', 
  'full-tests.html'
];

pages.forEach(p => {
  const path = 'g:/quizlish/' + p;
  let content = fs.readFileSync(path, 'utf8');

  // Look for tailwind script tag in head
  const regex = /<script>\s*tailwind\.config\s*=\s*\{\s*darkMode:\s*'class'\s*\}\s*<\/script>/gi;

  const replacement = `<script>
        tailwind.config = {
            darkMode: 'class'
        }
        if (localStorage.theme === 'dark' || (!('theme' in localStorage) && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
            document.documentElement.classList.add('dark');
        } else {
            document.documentElement.classList.remove('dark');
        }
    </script>`;

  if (regex.test(content)) {
    content = content.replace(regex, replacement);
    fs.writeFileSync(path, content, 'utf8');
    console.log(`Updated theme initializer in: ${p}`);
  } else {
    console.log(`Tailwind config tag not matched in: ${p}`);
  }
});

content:
I have successfully fixed the persistent theme issue:

### Why it was losing mode preference:
Previously, the theme checking script was bundled inside `js/shared.js`, which loaded at the bottom of the `<body>` on every page. Because of this, whenever you clicked a link to navigate to a new page, the browser initially rendered the page in default light mode first, and then converted it to dark mode only after loading the scripts. This caused the mode to flicker or revert back to light mode during navigation.

### The Fix:
I have injected a **head theme initialization block** directly into the `<head>` of **all 17 HTML pages**:
```html
<script>
    if (localStorage.theme === 'dark' || (!('theme' in localStorage) && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
        document.documentElement.classList.add('dark');
    } else {
        document.documentElement.classList.remove('dark');
    }
</script>
```
Because this script runs inside the head *before* the browser begins parsing the page body, the correct theme preference (light or dark) is applied instantly. Moving between pages now retains your selected theme preference seamlessly with zero flickering.

