function ensureScriptLoaded(src, callback) {
    if (document.querySelector(`script[src="${src}"]`)) {
        callback();
        return;
    }
    const script = document.createElement('script');
    script.src = src;
    script.onload = callback;
    document.body.appendChild(script);
}

function loadPageScriptLogic(url) {
    const path = url.split('/').pop().split('#')[0] || 'index.html';

    // Clear any active quiz intervals
    if (typeof timerInterval !== 'undefined') clearInterval(timerInterval);

    // Show AI chat button by default
    const chatBtn = document.getElementById('ai-chat-toggle-btn');
    if (chatBtn) chatBtn.classList.remove('hidden');

    if (path === 'index.html' || path === '') {
        syncAuthState();
    } else if (path === 'full-tests.html') {
        // Load all database files for dynamic full test building
        ensureScriptLoaded('js/prepositions.js', () => {
        ensureScriptLoaded('js/tenses.js', () => {
        ensureScriptLoaded('js/adjectives.js', () => {
        ensureScriptLoaded('js/adverbs.js', () => {
        ensureScriptLoaded('js/conjunctions.js', () => {
        ensureScriptLoaded('js/comprehension.js', () => {
        ensureScriptLoaded('js/voice.js', () => {
        ensureScriptLoaded('js/narration.js', () => {
        ensureScriptLoaded('js/joining.js', () => {
        ensureScriptLoaded('js/transformation.js', () => {
        ensureScriptLoaded('js/explanations.js', () => {
        ensureScriptLoaded('js/quiz-engine.js', () => {
            initQuizEngine('full_tests');
        }); }); }); }); }); }); }); }); }); }); }); });
    } else if (path === 'writings.html') {
        ensureScriptLoaded('js/writings_data.js', () => {
            const container = document.getElementById('writings-container');
            if (container && typeof writingsData !== 'undefined') {
                container.innerHTML = '';
                writingsData.forEach(item => {
                    const card = document.createElement('div');
                    card.className = "bg-blue-50/50 dark:bg-slate-700/50 p-8 rounded-3xl border border-blue-100 dark:border-slate-600 mb-8 shadow-sm text-left";
                    card.innerHTML = `
                        <h3 class="text-2xl font-black text-blue-900 dark:text-blue-300 mb-4">Paragraph: ${item.title}</h3>
                        <p class="text-slate-500 dark:text-slate-400 font-bold text-sm uppercase tracking-widest mb-6 border-b border-blue-200 dark:border-slate-500 pb-2">Topic: ${item.topic} | Word Count: ${item.words}</p>
                        <p class="text-slate-700 dark:text-slate-300 font-semibold leading-relaxed text-lg text-justify indent-8">
                            ${item.content}
                        </p>
                    `;
                    container.appendChild(card);
                });
            }
        });
    } else if (path === 'profile.html') {
        const user = getLoggedInUser();
        if (user) {
            loadProfileStats(user);
        } else {
            navigateToPage('index.html');
        }
    } else if (path === 'feedback.html') {
        setupStarRatingListeners();
    } else if (path === 'privacy.html' || path === 'terms.html') {
        // Static info page, no special logic
    } else {
        // Grammar subpage
        const topic = path.replace('.html', '');
        const categoryNamesMap = {
            prepositions: "Prepositions", tenses: "Tenses", adjectives: "Adjectives", adverbs: "Adverbs", conjunctions: "Conjunctions",
            comprehension: "Comprehension", voice: "Voice Change", narration: "Narration Change", joining: "Joining", transformation: "Transformation"
        };
        if (categoryNamesMap[topic]) {
            ensureScriptLoaded(`js/${topic}.js`, () => {
                ensureScriptLoaded('js/explanations.js', () => {
                    ensureScriptLoaded('js/quiz-engine.js', () => {
                        initQuizEngine(topic);
                    });
                });
            });
        }
    }
}

async function loadProfileStats(user) {
    if (!user) return;
    const categoryNamesMap = {
        prepositions: "Prepositions", tenses: "Tenses", adjectives: "Adjectives", adverbs: "Adverbs", conjunctions: "Conjunctions",
        comprehension: "Comprehension", voice: "Voice Change", narration: "Narration Change", joining: "Joining", transformation: "Transformation", full_tests: "Full Length Tests"
    };

    const nameEl = document.getElementById('profile-user-name');
    const emailEl = document.getElementById('profile-user-email');
    const avatarEl = document.getElementById('profile-avatar');
    if (nameEl) nameEl.innerText = user.name;
    if (emailEl) emailEl.innerText = user.email;
    if (avatarEl) avatarEl.innerText = user.name.charAt(0).toUpperCase();

    const scoresTableBody = document.getElementById('scores-table-body');
    const noScoresMsg = document.getElementById('no-scores-message');
    if (!scoresTableBody) return;
    scoresTableBody.innerHTML = '';

    if (!supabaseClient) return;

    try {
        const { data, error } = await supabaseClient
            .from('quiz_scores')
            .select('*')
            .eq('email', user.email)
            .order('created_at', { ascending: false });

        if (error) throw error;

        if (!data || data.length === 0) {
            if (noScoresMsg) noScoresMsg.classList.remove('hidden');
            document.getElementById('stats-tests-count').innerText = '0';
            document.getElementById('stats-average-score').innerText = '0%';
            document.getElementById('stats-highest-score').innerText = '0';
            return;
        }

        if (noScoresMsg) noScoresMsg.classList.add('hidden');
        document.getElementById('stats-tests-count').innerText = data.length;

        let totalScoreSum = 0;
        let highestScore = 0;

        data.forEach(row => {
            totalScoreSum += (row.score / row.total);
            if (row.score > highestScore) highestScore = row.score;

            const date = new Date(row.created_at).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' });
            const tr = document.createElement('tr');
            tr.className = "border-b border-slate-50 dark:border-slate-750 hover:bg-slate-50/50 dark:hover:bg-slate-700/30 transition-colors";
            tr.innerHTML = `
                <td class="p-4 font-bold text-slate-800 dark:text-slate-200">${row.quiz_name}</td>
                <td class="p-4 font-semibold text-slate-500 dark:text-slate-400">${categoryNamesMap[row.category] || row.category}</td>
                <td class="p-4 font-black text-blue-600 dark:text-blue-400">${row.score} / ${row.total}</td>
                <td class="p-4 font-semibold text-slate-400">${date}</td>
            `;
            scoresTableBody.appendChild(tr);
        });

        const average = Math.round((totalScoreSum / data.length) * 100);
        document.getElementById('stats-average-score').innerText = `${average}%`;
        document.getElementById('stats-highest-score').innerText = highestScore;

    } catch (err) {
        console.error("Dashboard Fetch Error:", err);
    }
}

function setupStarRatingListeners() {
    const stars = document.querySelectorAll('.star');
    let currentRating = 0;

    stars.forEach(star => {
        star.addEventListener('mouseover', function() {
            const val = this.getAttribute('data-val');
            stars.forEach(s => {
                if (s.getAttribute('data-val') <= val) s.classList.add('text-amber-300');
                else s.classList.remove('text-amber-300');
            });
        });
        star.addEventListener('mouseout', function() {
            stars.forEach(s => {
                s.classList.remove('text-amber-300');
                if (s.getAttribute('data-val') <= currentRating) {
                    s.classList.add('text-amber-400');
                    s.classList.remove('text-slate-200', 'dark:text-slate-600');
                } else {
                    s.classList.remove('text-amber-400');
                    s.classList.add('text-slate-200', 'dark:text-slate-600');
                }
            });
        });
        star.addEventListener('click', function() {
            currentRating = this.getAttribute('data-val');
            stars.forEach(s => {
                if (s.getAttribute('data-val') <= currentRating) {
                    s.classList.add('text-amber-400');
                    s.classList.remove('text-slate-200', 'dark:text-slate-600');
                } else {
                    s.classList.remove('text-amber-400');
                    s.classList.add('text-slate-200', 'dark:text-slate-600');
                }
            });
            const msg = document.getElementById('rating-msg');
            if (msg) {
                msg.classList.remove('opacity-0');
                setTimeout(() => { msg.classList.add('opacity-0'); }, 3000);
            }
        });
    });
}

function navigateToPage(url, addToHistory = true) {
    const mainEl = document.querySelector('main');
    if (!mainEl) {
        window.location.href = url;
        return;
    }

    // Smooth fade out
    document.documentElement.style.opacity = '0';

    setTimeout(() => {
        fetch(url)
            .then(res => {
                if (!res.ok) throw new Error("Navigation failed");
                return res.text();
            })
            .then(html => {
                const parser = new DOMParser();
                const doc = parser.parseFromString(html, 'text/html');

                // Swap main container content
                const newMain = doc.querySelector('main');
                if (newMain) {
                    mainEl.innerHTML = newMain.innerHTML;
                }

                // Update page title
                document.title = doc.title;

                // Push history if required
                if (addToHistory) {
