        if (localStorage.theme === 'dark' || (!('theme' in localStorage) && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
            document.documentElement.classList.add('dark');
        } else {
            document.documentElement.classList.remove('dark');
        }
    </script>`;

  const replacementScript = `<script>
        tailwind.config = {
            darkMode: 'class'
        }
        try {
            const theme = localStorage.getItem('theme');
            const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
            if (theme === 'dark' || (!theme && prefersDark)) {
                document.documentElement.classList.add('dark');
            } else {
                document.documentElement.classList.remove('dark');
            }
        } catch (e) {
            console.error('Theme retrieval failed:', e);
        }
    </script>`;

  if (content.includes(searchStr)) {
    content = content.replace(targetScript, replacementScript);
    fs.writeFileSync(path, content, 'utf8');
    console.log(`Standardized head theme script in: ${p}`);
  } else {
    // Try simple regex replace if string match varies
    const regex = /if\s*\(localStorage\.theme\s*===\s*'dark'[\s\S]*?document\.documentElement\.classList\.remove\('dark'\);\s*\}/gi;
    if (regex.test(content)) {
      content = content.replace(regex, `try {
            const theme = localStorage.getItem('theme');
            const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
            if (theme === 'dark' || (!theme && prefersDark)) {
                document.documentElement.classList.add('dark');
            } else {
                document.documentElement.classList.remove('dark');
            }
        } catch (e) {}`);
      fs.writeFileSync(path, content, 'utf8');
      console.log(`Standardized head theme script via regex in: ${p}`);
    } else {
      console.log(`No match for customization in: ${p}`);
    }
  }
});

