const fs = require('fs');

const pages = [
  'index.html', 'privacy.html', 'terms.html', 'feedback.html', 
  'writings.html', 'profile.html', 'prepositions.html', 'tenses.html', 
  'adjectives.html', 'adverbs.html', 'conjunctions.html', 'voice.html', 
  'narration.html', 'joining.html', 'transformation.html', 'comprehension.html', 
  'full-tests.html'
];

// 1. Process HTML Files to clean heads
pages.forEach(p => {
  const path = 'g:/quizlish/' + p;
  let content = fs.readFileSync(path, 'utf8');

  // Replace the theme setup block with standard tailwind config only
  const regex = /<script>\s*tailwind\.config\s*=\s*\{\s*darkMode:\s*'class'\s*\}[\s\S]*?<\/script>/gi;
  const standardConfig = `<script>
        tailwind.config = {
            darkMode: 'class'
        }
    </script>`;

  if (regex.test(content)) {
    content = content.replace(regex, standardConfig);
    fs.writeFileSync(path, content, 'utf8');
    console.log(`Cleaned head theme script in: ${p}`);
  }
});

// 2. Process shared.js to remove button & functions
const sharedPath = 'g:/quizlish/js/shared.js';
if (fs.existsSync(sharedPath)) {
  let content = fs.readFileSync(sharedPath, 'utf8');

  // Remove theme button
  const buttonRegex = /<button onclick="toggleTheme\(\)"[\s\S]*?<\/button>\s*/gi;
  content = content.replace(buttonRegex, '');

  // Remove toggleTheme function & Initial theme apply block
  const fnRegex = /\/\/ Theme manager[\s\S]*?\/\/ Initial theme apply[\s\S]*?\}\s*catch\s*\(e\)\s*\{\}/gi;
  content = content.replace(fnRegex, '');

  fs.writeFileSync(sharedPath, content, 'utf8');
  console.log('Cleaned shared.js theme logic and controls.');
}

